```class Solution {
public:
    int findKthNumber(int n, int k) {
        int result = n;
        for (int i = n - 1; i >= 1; i--) {
            for (int j = 1; j <= k; j++) {
                result = i * (result + 1);
            }
        }
        return result;
    }
};```

